<template><main class="game-root"><section v-if="stage==='home'" class="home-panel"><p class="eyebrow">CLEAN IMAGE BUILD</p><h1>Clean Image Run Gun</h1><p>Player and enemy use SVG sprite images with canvas drawImage.</p><button class="primary-btn" @click="startGame">Start</button></section><section v-else class="run-screen"><canvas ref="canvasRef" class="run-canvas" width="960" height="540"></canvas><div class="hud top-left"><p class="eyebrow">MISSION</p><strong>{{status.message}}</strong></div><div class="hud top-right"><span>HP: {{status.hp}}</span><span>Lives: {{status.lives}}</span><span>Score: {{status.score}}</span></div><div class="hud bottom-left"><strong>Controls</strong><span>A/D or arrows: move</span><span>W/K/up: jump</span><span>J/X/Ctrl: shoot</span></div><button class="exit-btn" @click="backHome">Exit</button></section></main></template><script setup lang="ts">import{nextTick,onBeforeUnmount,reactive,ref}from'vue';import{RunGunGame}from'./game/CleanRunGun';const stage=ref<'home'|'game'>('home');const canvasRef=ref<HTMLCanvasElement|null>(null);const status=reactive({hp:100,lives:3,score:0,message:'Ready.',state:'playing' as 'playing'|'win'|'lose'});let game:RunGunGame|null=null;async function startGame(){stage.value='game';await nextTick();if(!canvasRef.value)return;game?.destroy();game=new RunGunGame(canvasRef.value,{onStatus:v=>{status.hp=v.hp;status.lives=v.lives;status.score=v.score;status.message=v.message;status.state=v.state;}});game.start();}function backHome(){game?.destroy();game=null;stage.value='home';}onBeforeUnmount(()=>game?.destroy());</script>
